"""Database client module — synchronous implementation."""
import time


class DatabaseError(Exception):
    """Raised when a database operation fails."""
    pass


class Database:
    """Synchronous database client."""

    def __init__(self, host='localhost', port=5432):
        self.host = host
        self.port = port
        self._connected = False
        self._tables = {}

    def connect(self):
        """Connect to the database."""
        time.sleep(0.01)  # simulate network
        self._connected = True
        return self

    def query(self, table, filter_dict=None):
        """Query rows from a table with optional filter."""
        if not self._connected:
            raise DatabaseError("Not connected")
        time.sleep(0.01)  # simulate I/O
        rows = self._tables.get(table, [])
        if filter_dict:
            rows = [
                r for r in rows
                if all(r.get(k) == v for k, v in filter_dict.items())
            ]
        return list(rows)

    def insert(self, table, data):
        """Insert a row into a table."""
        if not self._connected:
            raise DatabaseError("Not connected")
        time.sleep(0.01)  # simulate I/O
        if table not in self._tables:
            self._tables[table] = []
        row = dict(data)
        self._tables[table].append(row)
        return row

    def close(self):
        """Close the database connection."""
        time.sleep(0.01)  # simulate network
        self._connected = False
        self._tables = {}

