"""Cache layer module — synchronous implementation."""
import time


class Cache:
    """Synchronous in-memory cache with simulated latency."""

    def __init__(self, prefix='app'):
        self.prefix = prefix
        self._store = {}

    def _make_key(self, key):
        return f"{self.prefix}:{key}"

    def get(self, key):
        """Get a value from cache. Returns None if not found."""
        time.sleep(0.01)  # simulate I/O
        full_key = self._make_key(key)
        return self._store.get(full_key)

    def set(self, key, value, ttl=None):
        """Set a value in cache."""
        time.sleep(0.01)  # simulate I/O
        full_key = self._make_key(key)
        self._store[full_key] = value
        return True

    def invalidate(self, key):
        """Remove a key from cache."""
        time.sleep(0.01)  # simulate I/O
        full_key = self._make_key(key)
        if full_key in self._store:
            del self._store[full_key]
            return True
        return False

    def flush(self):
        """Clear all cached data."""
        time.sleep(0.01)  # simulate I/O
        count = len(self._store)
        self._store = {}
        return count
